// ── Load config.json from Scriptable's iCloud folder ────────────
// config.json lives in: Files app > iCloud Drive > Scriptable > config.json
// It is gitignored and never pushed to GitHub.
let LINE_ID, HOME_STOP, DEST_STOP, USE_LIVE_API, API_KEY;

try {
  const fm         = FileManager.iCloud();
  const configPath = fm.joinPath(fm.documentsDirectory(), "config.json");

  if (fm.fileExists(configPath)) {
    // Download from iCloud if not yet local
    if (!fm.isFileDownloaded(configPath)) await fm.downloadFileFromiCloud(configPath);
    const cfg = JSON.parse(fm.readString(configPath));

    LINE_ID      = cfg.line       || DEFAULT_LINE_ID;
    HOME_STOP    = cfg.homeStop   || DEFAULT_HOME_STOP;
    DEST_STOP    = cfg.destStop   || DEFAULT_DEST_STOP;
    USE_LIVE_API = cfg.useLiveApi || false;
    API_KEY      = cfg.apiKey     || "";
  } else {
    throw new Error("config.json not found");
  }
} catch(e) {
  // config.json missing or unreadable — use fallback constants above
  LINE_ID      = DEFAULT_LINE_ID;
  HOME_STOP    = DEFAULT_HOME_STOP;
  DEST_STOP    = DEFAULT_DEST_STOP;
  USE_LIVE_API = false;
  API_KEY      = "";
}

const API_BASE = "https://api.openmetrolinx.com/OpenDataAPI/api/V1";

