// ── Helpers ──────────────────────────────────────────────────────

function scheduleKey(date) {
  const d = date.getDay();
  if (d === 0) return "sunday";
  if (d === 6) return "saturday";
  if (d === 5) return "friday";
  return "weekday";
}

function parseMinutes(hhmm) {
  const [h, m] = hhmm.split(":").map(Number);
  return h * 60 + m;
}

function minutesUntil(trainMins, nowMins) {
  let diff = trainMins - nowMins;
  if (diff < 0) diff += 1440;
  return diff;
}

function formatTime12(hhmm) {
  const [h, m] = hhmm.split(":").map(Number);
  const ampm = h < 12 ? "AM" : "PM";
  const hour = h % 12 || 12;
  return `${hour}:${String(m).padStart(2, "0")} ${ampm}`;
}

function formatCountdown(mins) {
  if (mins < 1)  return "Now";
  if (mins < 60) return `${mins} min`;
  const h = Math.floor(mins / 60), m = mins % 60;
  return m === 0 ? `${h}h` : `${h}h ${m}m`;
}

function haversineKm(lat1, lon1, lat2, lon2) {
  const R = 6371, r = x => x * Math.PI / 180;
  const dLat = r(lat2 - lat1), dLon = r(lon2 - lon1);
  const a = Math.sin(dLat/2)**2 + Math.cos(r(lat1)) * Math.cos(r(lat2)) * Math.sin(dLon/2)**2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

// Returns "inbound" or "outbound" for travelling fromId → toId on a line
function directionFor(line, fromId, toId) {
  const stops = line.stops;
  return stops.findIndex(s => s.id === fromId) < stops.findIndex(s => s.id === toId)
    ? "inbound" : "outbound";
}

// Returns next N departures from a stop in a given direction
function getNextTrains(line, stopId, direction, count) {
  const skey  = scheduleKey(new Date());
  const sched = line.schedule[skey];
  if (!sched) return [];                         // no service this day type
  const times = (sched[direction] || {})[stopId] || [];
  const now   = new Date();
  const nowM  = now.getHours() * 60 + now.getMinutes();
  return times
    .map(t => ({ time: t, wait: minutesUntil(parseMinutes(t), nowM) }))
    .sort((a, b) => a.wait - b.wait)
    .slice(0, count);
}

// ── Live API fetch (used when USE_LIVE_API = true) ────────────────
// Calls: GET /api/V1/Stop/NextService/{StopCode}
// Returns an array of { time, wait } objects in the same format as getNextTrains()
async function fetchLiveTrains(stopCode, destStopCode, count) {
  const url = `${API_BASE}/Stop/NextService/${stopCode}?key=${API_KEY}`;
  try {
    const req  = new Request(url);
    const json = await req.loadJSON();
    // The API returns departures for ALL lines at the stop.
    // Filter to only trips whose destination matches destStopCode or is Union (UN).
    // Adjust the response parsing below if Metrolinx changes their schema.
    const departures = (json.NextService || json.Departures || []);
    const now = new Date();
    const nowM = now.getHours() * 60 + now.getMinutes();
    return departures
      .slice(0, count)
      .map(d => {
        // API returns scheduled time as "HH:MM" or ISO string — adapt as needed
        const time = d.ScheduledDepartureTime || d.Time || "";
        const hhmm = time.length > 5 ? time.slice(11, 16) : time;
        return { time: hhmm, wait: minutesUntil(parseMinutes(hhmm), nowM) };
      });
  } catch(e) {
    // If the API call fails, fall back to hardcoded schedule silently
    return null;
  }
}

// ── Widget builder ────────────────────────────────────────────────

async function buildWidget(fromStopId, toStopId, line, usingGPS) {
  const fromStop = line.stops.find(s => s.id === fromStopId);
  const toStop   = line.stops.find(s => s.id === toStopId);
  const direction = directionFor(line, fromStopId, toStopId);

  // Decide how many trains to show based on widget size
  const widgetFamily = config.widgetFamily;
  const trainCount   = widgetFamily === "small" ? 2 : (widgetFamily === "large" ? 5 : 3);

  // Get departures — live API or hardcoded schedule
  let trains;
  if (USE_LIVE_API && API_KEY !== "YOUR_API_KEY_HERE") {
    trains = await fetchLiveTrains(fromStopId, toStopId, trainCount);
    if (!trains) trains = getNextTrains(line, fromStopId, direction, trainCount); // fallback
  } else {
    // Using hardcoded GTFS schedule data
    trains = getNextTrains(line, fromStopId, direction, trainCount);
  }

  // ── Build widget UI ─────────────────────────────────────────────
  const w = new ListWidget();
  w.backgroundColor = new Color("#161b22");
  w.setPadding(12, 14, 12, 14);
  w.spacing = 6;

  // Header row: coloured dot + line name
  const header = w.addStack();
  header.layoutHorizontally();
  header.centerAlignContent();
  header.spacing = 6;

  const dot = header.addText("●");
  dot.textColor = new Color(line.color);
  dot.font = Font.systemFont(10);

  const lineName = header.addText(line.name);
  lineName.textColor = new Color("#8b949e");
  lineName.font = Font.mediumSystemFont(11);

  if (usingGPS) {
    header.addSpacer();
    const gpsIcon = header.addText("⌖");
    gpsIcon.textColor = new Color("#8b949e");
    gpsIcon.font = Font.systemFont(10);
  }

  w.addSpacer(2);

  // Departing from label
  const fromLabel = w.addText("From " + fromStop.name.replace(" GO","").replace(" GO Station Rail",""));
  fromLabel.textColor = new Color("#e6edf3");
  fromLabel.font = Font.boldSystemFont(13);
  fromLabel.lineLimit = 1;

  // Towards label
  const toLabel = w.addText("→ " + toStop.name.replace(" GO","").replace(" GO Station Rail",""));
  toLabel.textColor = new Color(line.color);
  toLabel.font = Font.systemFont(11);

  w.addSpacer(4);

  // Train rows
  if (!trains || trains.length === 0) {
    const noSvc = w.addText("No service today");
    noSvc.textColor = new Color("#8b949e");
    noSvc.font = Font.systemFont(12);
  } else {
    trains.forEach((t, i) => {
      const row = w.addStack();
      row.layoutHorizontally();
      row.centerAlignContent();

      // Highlight first (soonest) train in green
      const highlight = i === 0;
      const colour    = highlight ? new Color("#3fb950") : new Color("#e6edf3");
      const countdownColour = highlight ? new Color("#3fb950") : new Color("#8b949e");

      const timeText = row.addText(formatTime12(t.time));
      timeText.textColor = colour;
      timeText.font = Font.boldMonospacedSystemFont(15);

      row.addSpacer();

      const countdown = row.addText(formatCountdown(t.wait));
      countdown.textColor = countdownColour;
      countdown.font = Font.mediumSystemFont(12);
    });
  }

  // Data source note at the bottom
  w.addSpacer();
  const footer = w.addText(USE_LIVE_API ? "Live data" : "Scheduled · gotransit.com");
  footer.textColor = new Color("#484f58");
  footer.font = Font.systemFont(9);

  return w;
}

// ── Main ──────────────────────────────────────────────────────────

async function main() {
  const line = LINES[LINE_ID];
  if (!line) {
    const w = new ListWidget();
    w.backgroundColor = new Color("#161b22");
    const err = w.addText(`Unknown line: ${LINE_ID}`);
    err.textColor = Color.red();
    Script.setWidget(w);
    Script.complete();
    return;
  }

  let fromStopId = HOME_STOP;
  let toStopId   = DEST_STOP;
  let usingGPS   = false;

  // Try GPS: if we can get location, detect which station we're closer to
  // and automatically flip direction for the return commute
  try {
    Location.setAccuracyToHundredMeters();
    const loc      = await Location.current();
    const homeStop = line.stops.find(s => s.id === HOME_STOP);
    const destStop = line.stops.find(s => s.id === DEST_STOP);

    const dHome = haversineKm(loc.latitude, loc.longitude, homeStop.lat, homeStop.lon);
    const dDest = haversineKm(loc.latitude, loc.longitude, destStop.lat, destStop.lon);

    if (dDest < dHome) {
      // Closer to destination — show return trains
      fromStopId = DEST_STOP;
      toStopId   = HOME_STOP;
    }
    usingGPS = true;
  } catch(e) {
    // GPS unavailable or permission denied — default to home → destination
    usingGPS = false;
  }

  const widget = await buildWidget(fromStopId, toStopId, line, usingGPS);

  // Run in widget or preview in app
  if (config.runsInWidget) {
    Script.setWidget(widget);
  } else {
    // When running inside Scriptable app, show a preview
    const family = config.widgetFamily || "medium";
    if (family === "small")  await widget.presentSmall();
    else if (family === "large") await widget.presentLarge();
    else await widget.presentMedium();
  }

  Script.complete();
}

await main();
